#include <map>

map<string, int> ages;

ages["Aman"] = 20;   // insert or update
ages["Priya"] = 22;

cout << ages["Aman"]; // 20 — access by key

map<string, int> ages;
ages["Aman"] = 20;

cout << ages["Ghost"]; // "Ghost" doesn't exist — but this doesn't error!
cout << ages.size();   // 2 — "Ghost" got silently ADDED with value 0

map<string, int> ages;
ages["Aman"] = 20;

if (ages.count("Ghost") == 0)
{
    cout << "Not found — and nothing was inserted.";
}

#include <iostream>
#include <map>
#include <string>

using namespace std;

int main()
{
    map<string, int> ages;
    ages["Priya"] = 22;
    ages["Aman"] = 20;
    ages["Zara"] = 25;

    for (auto pair : ages)
    {
        cout << pair.first << ": " << pair.second << endl;
    }

    return 0;
}

